import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { deleteSale, getSales } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

export default function SaleList() {
  const [sales, setSales] = useState([]);
  const navigate = useNavigate();

  const { role } = getAuth();
  const canManage = role === "admin" || role === "manager";

  const load = async () => {
    try {
      const res = await getSales();
      setSales(res.data);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load sales");
    }
  };

  useEffect(() => {
    load();
  }, []);

  const onDelete = async (id) => {
    if (!canManage) return alert("Access denied");
    if (!window.confirm("Delete this sale record?")) return;

    try {
      await deleteSale(id);
      setSales((prev) => prev.filter((s) => s._id !== id));
      alert("Deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Sales Transactions</h2>

        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={load}>Refresh</button>
          {canManage && (
            <Link to="/sales/add">
              <button>+ Add Sale</button>
            </Link>
          )}
        </div>
      </div>

      <table border="1" cellPadding="10" style={{ width: "100%", marginTop: 12, textAlign: "left" }}>
        <thead>
          <tr>
            <th>Vehicle</th>
            <th>Deal</th>
            <th>Payment</th>
            <th>Final Price</th>
            <th>Paid</th>
            <th>Date</th>
            <th style={{ width: 200 }}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {sales.map((s) => (
            <tr key={s._id}>
              <td>
                {s.vehicle?.brand
                  ? `${s.vehicle.brand} ${s.vehicle.model || s.vehicle.type || ""}`
                  : "-"}
              </td>
              <td>{s.dealStatus}</td>
              <td>{s.paymentStatus}</td>
              <td>{s.finalPrice ? `Rs. ${Number(s.finalPrice).toLocaleString()}` : "-"}</td>
              <td>{`Rs. ${Number(s.paidAmount || 0).toLocaleString()}`}</td>
              <td>{new Date(s.createdAt).toLocaleDateString()}</td>
              <td>
                <button onClick={() => navigate(`/sales/view/${s._id}`)}>View</button>

                {canManage && (
                  <>
                    <button style={{ marginLeft: 6 }} onClick={() => navigate(`/sales/edit/${s._id}`)}>
                      Edit
                    </button>
                    <button style={{ marginLeft: 6 }} onClick={() => onDelete(s._id)}>
                      Delete
                    </button>
                  </>
                )}
              </td>
            </tr>
          ))}
          {sales.length === 0 && (
            <tr>
              <td colSpan="7">No sales found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}
